CREATE TABLE hdb_catalog.hdb_action_permission
(
  action_name TEXT NOT NULL,
  role_name TEXT NOT NULL,
  definition JSONB NOT NULL DEFAULT '{}'::jsonb,
  PRIMARY KEY (action_name, role_name),
  FOREIGN KEY (action_name) REFERENCES hdb_catalog.hdb_action(action_name) ON UPDATE CASCADE
);

CREATE VIEW hdb_catalog.hdb_role AS (
  SELECT DISTINCT role_name FROM (
    SELECT role_name FROM hdb_catalog.hdb_permission
    UNION ALL
    SELECT role_name FROM hdb_catalog.hdb_action_permission
  ) q
);

CREATE OR REPLACE FUNCTION _timescaledb_functions.align_to_bucket(width interval, rng anyrange)
RETURNS anyrange AS
$body$
BEGIN
  RETURN _timescaledb_functions.make_range_from_internal_time(
         rng,
         @extschema@.time_bucket(width, lower(rng)),
         @extschema@.time_bucket(width, upper(rng) - '1 microsecond'::interval) + width
  );
END
$body$
LANGUAGE plpgsql IMMUTABLE STRICT PARALLEL SAFE
SET search_path TO pg_catalog, pg_temp;

DROP EVENT TRIGGER IF EXISTS timescaledb_ddl_command_end;

CREATE OR REPLACE FUNCTION _timescaledb_functions.process_ddl_event() RETURNS event_trigger
AS '@MODULE_PATHNAME@', 'ts_timescaledb_process_ddl_event' LANGUAGE C;

CREATE EVENT TRIGGER timescaledb_ddl_command_end ON ddl_command_end
WHEN TAG IN ('ALTER TABLE','CREATE TRIGGER','CREATE TABLE','CREATE INDEX','ALTER INDEX', 'DROP TABLE', 'DROP INDEX', 'DROP SCHEMA')
EXECUTE FUNCTION _timescaledb_functions.process_ddl_event();

DROP EVENT TRIGGER IF EXISTS timescaledb_ddl_sql_drop;
CREATE EVENT TRIGGER timescaledb_ddl_sql_drop ON sql_drop
EXECUTE FUNCTION _timescaledb_functions.process_ddl_event();

-- Phase B: Change worksheet PK to resource_id
DO $$ BEGIN
    IF NOT EXISTS (
        SELECT 1 FROM pg_constraint
        WHERE conname = 'worksheet_pkey' AND conrelid = 'worksheet'::regclass
          AND array_length(conkey, 1) = 1
          AND conkey[1] = (SELECT attnum FROM pg_attribute WHERE attrelid = 'worksheet'::regclass AND attname = 'resource_id')
    ) THEN
        ALTER TABLE worksheet DROP CONSTRAINT IF EXISTS worksheet_pkey;
        ALTER TABLE worksheet ADD PRIMARY KEY (resource_id);
    END IF;
END $$

-- Add foreign key constraints back to compressed chunks
DO $$
DECLARE
  chunkrelid regclass;
  conname name;
  conoid oid;
BEGIN
  FOR chunkrelid, conname, conoid IN
  SELECT format('%I.%I',ch.schema_name,ch.table_name)::regclass, con.conname, con.oid
  FROM _timescaledb_catalog.hypertable ht
  JOIN pg_constraint con ON con.contype = 'f' AND con.conrelid=format('%I.%I',ht.schema_name,ht.table_name)::regclass
  JOIN _timescaledb_catalog.chunk ch on ch.hypertable_id=ht.compressed_hypertable_id and not ch.dropped
  LOOP
    EXECUTE format('ALTER TABLE %s ADD CONSTRAINT %I %s', chunkrelid, conname, pg_get_constraintdef(conoid));
  END LOOP;
END $$;

-- Phase B: Add project columns and change PKs (top-down)

-- plan (already has project, just change PK)
DO $$ BEGIN
    IF NOT EXISTS (
        SELECT 1 FROM pg_constraint
        WHERE conname = 'plan_pkey'
          AND conrelid = 'plan'::regclass
          AND array_length(conkey, 1) = 2
    ) THEN
        ALTER TABLE plan DROP CONSTRAINT IF EXISTS plan_pkey;
        ALTER TABLE plan ADD PRIMARY KEY (project, id);
    END IF;
END $$

-- Phase B: Change issue PK
DO $$ BEGIN
    IF NOT EXISTS (
        SELECT 1 FROM pg_constraint
        WHERE conname = 'issue_pkey'
          AND conrelid = 'issue'::regclass
          AND array_length(conkey, 1) = 2
    ) THEN
        ALTER TABLE issue DROP CONSTRAINT IF EXISTS issue_pkey;
        ALTER TABLE issue ADD PRIMARY KEY (project, id);
    END IF;
END $$

-- Migrate name into payload.title if the name column still exists.
DO $$
BEGIN
    IF EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'workspace' AND column_name = 'name') THEN
        UPDATE workspace SET payload = jsonb_set(payload, '{title}', to_jsonb(name))
        WHERE payload->>'title' IS NULL OR payload->>'title' = '';
        ALTER TABLE workspace DROP COLUMN name;
    END IF;
END $$

